"""File I/O persistence for Library Management System."""import jsonfrom datetime import datetimefrom .models.book import Bookfrom .models.member import Memberfrom .models.loan import LoanRecordfrom .collections.book_collection import BookCollectionfrom .collections.member_collection import MemberCollectionfrom .collections.loan_collection import LoanCollectiondef save_data(book_collection, member_collection, loan_collection, filename="library_data.json"):    """    Save all collections to a JSON file.    Args:        book_collection: BookCollection instance        member_collection: MemberCollection instance        loan_collection: LoanCollection instance        filename: Output file path    """    data = {        "books": [],        "members": [],        "loans": []    }    # Serialize books    for book in book_collection.get_all_books():        data["books"].append({            "title": book.title,            "author": book.author,            "isbn": book.isbn,            "publication_year": book.publication_year,            "publisher": getattr(book, 'publisher', ''),            "genre": getattr(book, 'genre', 'General'),            "is_reference": book.is_reference,            "_is_checked_out": book._is_checked_out        })    # Serialize members    for member in member_collection.get_all_members():        data["members"].append({            "name": member.name,            "member_id": member.member_id,            "email": member.email,            "phone": member.phone,            "address": member.address,            "registration_date": member.registration_date.isoformat() if hasattr(member, 'registration_date') else None,            "_borrowed_books": member._borrowed_books,            "_fines_owed": member._fines_owed,            "_is_active": member._is_active        })    # Serialize loans    for loan in loan_collection.get_all_active_loans():        data["loans"].append({            "book_isbn": loan.book_isbn,            "member_id": loan.member_id,            "checkout_date": loan.checkout_date.isoformat(),            "due_date": loan.due_date.isoformat(),            "return_date": loan.return_date.isoformat() if loan.return_date else None,            "loan_id": loan.loan_id        })    with open(filename, 'w', encoding='utf-8') as f:        json.dump(data, f, indent=2)def load_data(filename="library_data.json"):    """    Load collections from a JSON file.    Returns:        tuple: (BookCollection, MemberCollection, LoanCollection) or None if file not found.    """    try:        with open(filename, 'r', encoding='utf-8') as f:            data = json.load(f)    except FileNotFoundError:        return None    books = BookCollection()    members = MemberCollection()    loans = LoanCollection()    for b in data.get("books", []):        book = Book(            title=b["title"],            author=b["author"],            isbn=b["isbn"],            publication_year=b["publication_year"],            is_reference=b.get("is_reference", False)        )        book._is_checked_out = b.get("_is_checked_out", False)        books.add_book(book)    for m in data.get("members", []):        member = Member(            name=m["name"],            member_id=m["member_id"],            email=m["email"],            phone=m.get("phone", ""),            address=m.get("address", "")        )        member._borrowed_books = m.get("_borrowed_books", [])        member._fines_owed = m.get("_fines_owed", 0.0)        member._is_active = m.get("_is_active", True)        members.add_member(member)    for l in data.get("loans", []):        loan = LoanRecord(            book_isbn=l["book_isbn"],            member_id=l["member_id"],            checkout_date=datetime.fromisoformat(l["checkout_date"]),            due_date=datetime.fromisoformat(l["due_date"]),            return_date=datetime.fromisoformat(l["return_date"]) if l["return_date"] else None,            loan_id=l.get("loan_id")        )        loans.add_loan(loan)    return books, members, loans